  'jacobiSC': { summary: 'Jacobi elliptic function sc = sn/cn', syntax: [] },
  'jacobiSD': { summary: 'Jacobi elliptic function sd = sn/dn', syntax: [] },
  'jacobiCD': { summary: 'Jacobi elliptic function cd = cn/dn', syntax: [] },
  'jacobiCS': { summary: 'Jacobi elliptic function cs = cn/sn', syntax: [] },
  'jacobiDC': { summary: 'Jacobi elliptic function dc = dn/cn', syntax: [] },
  'jacobiDS': { summary: 'Jacobi elliptic function ds = dn/sn', syntax: [] },
  'jacobiNC': { summary: 'Jacobi elliptic function nc = 1/cn', syntax: [] },
  'jacobiND': { summary: 'Jacobi elliptic function nd = 1/dn', syntax: [] },
  'jacobiNS': { summary: 'Jacobi elliptic function ns = 1/sn', syntax: [] },
