  'texlabel': { summary: 'Format symbolic expression as TeX', syntax: [], description: ['txt = texlabel(f) converts the MATLAB® expression f into the TeX equivalent for use in text. texlabel converts Greek variable names (for example, lambda, delta, and so on) into a character vector that is displayed as Greek letters. The txt output is useful as an argument to annotation functions such as title, xlabel, and text.', '[example](texlabel.html#btq_v1e-2_1)', 'txt = texlabel(f,\'literal\') interprets Greek variable names literally.', '[example](texlabel.html#btq_v1e-2_1)'] },
  'cell2sym': { summary: 'Convert a cell array to a symbolic array', syntax: [] },
  'sym2cell': { summary: 'Convert a symbolic array to a cell array', syntax: [] },
